Javascript.miscCode:
JudgmentSelection.srcData = REF_DATA_XPATH + "/Judgments";
JudgmentSelection.rowXPath = "Judgment[Status = 'SATISFIED' or Status = 'CANCELLED']";
JudgmentSelection.keyXPath = "JudgmentId";			
JudgmentSelection.columns = [
	{xpath: "Date", transformToDisplay : CaseManUtils.formatGridDate},
	{xpath: "PartyAgainstName"},
	{xpath: "AmountCurrency"},
	{xpath: "Amount", transformToDisplay : WPU.formatToTwoDP},
	{xpath: "Type"} ];
JudgmentSelection.multipleSelection = false;

Context.initialise:
WPU.createJudgmentList();
var selectedJudgment = Services.getValue("/ds/var/app/WPData/WordProcessing/Judgment/JudgSeq");
if ( null != selectedJudgment && "" != selectedJudgment )
{
	Services.setValue(JudgmentSelection.dataBinding, selectedJudgment);
}
